// Apply applies a list of actions (send, settle, mint, etc.) and returns the resulting balance deltas per asset.
func (o *Spends) Apply(actions []*Action) (*Deltas, error) {
	if o == nil {
		return nil, fmt.Errorf("object is nil or already freed")
	}
	o.mu.RLock()
	defer o.mu.RUnlock()
	if o.ptr == nil {
		return nil, fmt.Errorf("object is nil or already freed")
	}
	for i, item := range actions {
		if item == nil {
			return nil, fmt.Errorf("nil item in actions at index %d", i)
		}
	}
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	actionsPtrs := make([]unsafe.Pointer, len(actions))
	for i, item := range actions {
		actionsPtrs[i] = item.ptr
	}
	var actionsPtrsC *unsafe.Pointer
	if len(actionsPtrs) > 0 {
		actionsPtrsC = &actionsPtrs[0]
	}
	actionsLen := C.size_t(len(actions))

	var out unsafe.Pointer
	ret := C.go_spends_apply(o.ptr, (*unsafe.Pointer)(unsafe.Pointer(actionsPtrsC)), actionsLen, &out)
	runtime.KeepAlive(o)
	runtime.KeepAlive(actions)
	if ret != 0 {
		return nil, lastError()
	}
	obj := &Deltas{ptr: out}
	runtime.SetFinalizer(obj, (*Deltas).Free)
	return obj, nil
}

