// Vault represents a MIPS vault singleton coin with its lineage proof and configuration info.
//
// All methods are safe for concurrent use from multiple goroutines.
// Call [Free] or [Close] to release the underlying memory, or rely on the
// attached runtime finalizer for automatic cleanup.
type Vault struct {
	ptr unsafe.Pointer
	mu  sync.RWMutex
}

// Free releases the underlying Rust object.
// Calling Free more than once or on a nil receiver is safe and has no effect.
// Free blocks until any concurrent method calls complete.
func (o *Vault) Free() {
	if o == nil {
		return
	}
	o.mu.Lock()
	defer o.mu.Unlock()
	if o.ptr == nil {
		return
	}
	C.go_vault_free(o.ptr)
	o.ptr = nil
}

// Close implements [io.Closer] by releasing the underlying resource.
// It is safe to call Close multiple times and concurrently with other methods.
func (o *Vault) Close() error {
	o.Free()
	return nil
}

// Clone returns a deep copy of the Vault.
func (o *Vault) Clone() (*Vault, error) {
	if o == nil {
		return nil, fmt.Errorf("object is nil or already freed")
	}
	o.mu.RLock()
	defer o.mu.RUnlock()
	if o.ptr == nil {
		return nil, fmt.Errorf("object is nil or already freed")
	}
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	var out unsafe.Pointer
	ret := C.go_vault_clone(o.ptr, &out)
	if ret != 0 {
		return nil, lastError()
	}
	clone := &Vault{ptr: out}
	runtime.SetFinalizer(clone, (*Vault).Free)
	return clone, nil
}

// NewVault creates a new [Vault] with the given field values.
func NewVault(coin *Coin, proof *Proof, info *VaultInfo) (*Vault, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	if coin == nil {
		return nil, fmt.Errorf("coin must not be nil")
	}
	if proof == nil {
		return nil, fmt.Errorf("proof must not be nil")
	}
	if info == nil {
		return nil, fmt.Errorf("info must not be nil")
	}

	var out unsafe.Pointer
	ret := C.go_vault_new(coin.ptr, proof.ptr, info.ptr, &out)
	runtime.KeepAlive(coin)
	runtime.KeepAlive(proof)
	runtime.KeepAlive(info)
	if ret != 0 {
		return nil, lastError()
	}
	obj := &Vault{ptr: out}
	runtime.SetFinalizer(obj, (*Vault).Free)
	return obj, nil
}

