// SpendCoins spends coins using the given coin spends and BLS secret keys for signing, then creates a block.
func (o *Simulator) SpendCoins(coinSpends []*CoinSpend, secretKeys []*SecretKey) error {
	if o == nil {
		return fmt.Errorf("object is nil or already freed")
	}
	o.mu.RLock()
	defer o.mu.RUnlock()
	if o.ptr == nil {
		return fmt.Errorf("object is nil or already freed")
	}
	for i, item := range coinSpends {
		if item == nil {
			return fmt.Errorf("nil item in coinSpends at index %d", i)
		}
	}
	for i, item := range secretKeys {
		if item == nil {
			return fmt.Errorf("nil item in secretKeys at index %d", i)
		}
	}
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	coinSpendsPtrs := make([]unsafe.Pointer, len(coinSpends))
	for i, item := range coinSpends {
		coinSpendsPtrs[i] = item.ptr
	}
	var coinSpendsPtrsC *unsafe.Pointer
	if len(coinSpendsPtrs) > 0 {
		coinSpendsPtrsC = &coinSpendsPtrs[0]
	}
	coinSpendsLen := C.size_t(len(coinSpends))
	secretKeysPtrs := make([]unsafe.Pointer, len(secretKeys))
	for i, item := range secretKeys {
		secretKeysPtrs[i] = item.ptr
	}
	var secretKeysPtrsC *unsafe.Pointer
	if len(secretKeysPtrs) > 0 {
		secretKeysPtrsC = &secretKeysPtrs[0]
	}
	secretKeysLen := C.size_t(len(secretKeys))

	ret := C.go_simulator_spend_coins(o.ptr, (*unsafe.Pointer)(unsafe.Pointer(coinSpendsPtrsC)), coinSpendsLen, (*unsafe.Pointer)(unsafe.Pointer(secretKeysPtrsC)), secretKeysLen)
	runtime.KeepAlive(o)
	runtime.KeepAlive(coinSpends)
	runtime.KeepAlive(secretKeys)
	if ret != 0 {
		return lastError()
	}
	return nil
}

