// R1PairManyFromSeed derives multiple secp256r1 key pairs from a seed, each with a unique derivation index.
func R1PairManyFromSeed(seed uint64, count uint32) ([]*R1Pair, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()

	var out unsafe.Pointer
	ret := C.go_r_1_pair_many_from_seed(C.uint64_t(seed), C.uint32_t(count), &out)
	if ret != 0 {
		return nil, lastError()
	}
	listLen := C.go_r_1_pair_list_len(out)
	result := make([]*R1Pair, listLen)
	for i := range result {
		var itemPtr unsafe.Pointer
		if ret := C.go_r_1_pair_list_get(out, C.size_t(i), &itemPtr); ret != 0 {
			C.go_r_1_pair_list_free(out)
			return nil, lastError()
		}
		result[i] = &R1Pair{ptr: itemPtr}
		runtime.SetFinalizer(result[i], (*R1Pair).Free)
	}
	C.go_r_1_pair_list_free(out)
	return result, nil
}

// FromHex decodes a hexadecimal string into raw bytes.
func FromHex(value string) ([]byte, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	cValue := C.CString(value)
	defer C.free(unsafe.Pointer(cValue))
	var outPtr *C.uint8_t
	var outLen C.size_t
	ret := C.go_from_hex(cValue, &outPtr, &outLen)
	if ret != 0 {
		return nil, lastError()
	}
	result := C.GoBytes(unsafe.Pointer(outPtr), C.int(outLen))
	C.go_free_bytes((*C.uint8_t)(unsafe.Pointer(outPtr)), outLen)
	return result, nil
}

// ToHex encodes raw bytes as a hexadecimal string.
func ToHex(value []byte) (string, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	valuePtr, valueLen := bytesToPtr(value)

	var cOut *C.char
	ret := C.go_to_hex(valuePtr, valueLen, &cOut)
	if ret != 0 {
		return "", lastError()
	}
	result := C.GoString(cOut)
	C.go_free_string(cOut)
	return result, nil
}

// BytesEqual reports whether two byte slices are equal.
func BytesEqual(lhs []byte, rhs []byte) (bool, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	lhsPtr, lhsLen := bytesToPtr(lhs)
	rhsPtr, rhsLen := bytesToPtr(rhs)

	var cOut C.int
	ret := C.go_bytes_equal(lhsPtr, lhsLen, rhsPtr, rhsLen, &cOut)
	if ret != 0 {
		return false, lastError()
	}
	return cOut != 0, nil
}

