// SelectCoins selects the smallest set of coins that meets or exceeds the target amount using a knapsack algorithm.
func SelectCoins(coins []*Coin, amount uint64) ([]*Coin, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	for i, item := range coins {
		if item == nil {
			return nil, fmt.Errorf("nil item in coins at index %d", i)
		}
	}
	coinsPtrs := make([]unsafe.Pointer, len(coins))
	for i, item := range coins {
		coinsPtrs[i] = item.ptr
	}
	var coinsPtrsC *unsafe.Pointer
	if len(coinsPtrs) > 0 {
		coinsPtrsC = &coinsPtrs[0]
	}
	coinsLen := C.size_t(len(coins))

	var out unsafe.Pointer
	ret := C.go_select_coins((*unsafe.Pointer)(unsafe.Pointer(coinsPtrsC)), coinsLen, C.uint64_t(amount), &out)
	runtime.KeepAlive(coins)
	if ret != 0 {
		return nil, lastError()
	}
	listLen := C.go_coin_list_len(out)
	result := make([]*Coin, listLen)
	for i := range result {
		var itemPtr unsafe.Pointer
		if ret := C.go_coin_list_get(out, C.size_t(i), &itemPtr); ret != 0 {
			C.go_coin_list_free(out)
			return nil, lastError()
		}
		result[i] = &Coin{ptr: itemPtr}
		runtime.SetFinalizer(result[i], (*Coin).Free)
	}
	C.go_coin_list_free(out)
	return result, nil
}

// SpendBundleCost computes the total CLVM execution cost of the given coin spends.
func SpendBundleCost(coinSpends []*CoinSpend) (uint64, error) {
	runtime.LockOSThread()
	defer runtime.UnlockOSThread()
	for i, item := range coinSpends {
		if item == nil {
			return 0, fmt.Errorf("nil item in coinSpends at index %d", i)
		}
	}
	coinSpendsPtrs := make([]unsafe.Pointer, len(coinSpends))
	for i, item := range coinSpends {
		coinSpendsPtrs[i] = item.ptr
	}
	var coinSpendsPtrsC *unsafe.Pointer
	if len(coinSpendsPtrs) > 0 {
		coinSpendsPtrsC = &coinSpendsPtrs[0]
	}
	coinSpendsLen := C.size_t(len(coinSpends))

	var cOut C.uint64_t
	ret := C.go_spend_bundle_cost((*unsafe.Pointer)(unsafe.Pointer(coinSpendsPtrsC)), coinSpendsLen, &cOut)
	runtime.KeepAlive(coinSpends)
	if ret != 0 {
		return 0, lastError()
	}
	return uint64(cOut), nil
}
